import{_ as s,o as a,c as n,ag as i}from"./chunks/framework.CTpQozEL.js";const g=JSON.parse('{"title":"메시지","description":"메시지 흐름, 세션, 큐잉, reasoning 가시성","frontmatter":{"title":"메시지","description":"메시지 흐름, 세션, 큐잉, reasoning 가시성"},"headers":[],"relativePath":"concepts/messages.md","filePath":"concepts/messages.md","lastUpdated":null}'),l={name:"concepts/messages.md"};function o(t,e,c,d,p,r){return a(),n("div",null,[...e[0]||(e[0]=[i(`<p>이 페이지는 OpenClaw가 인바운드 메시지, 세션, 큐잉, 스트리밍, reasoning 가시성을 어떻게 처리하는지 한 자리에 모아 설명합니다.</p><h2 id="메시지-흐름-개요" tabindex="-1">메시지 흐름 (개요) <a class="header-anchor" href="#메시지-흐름-개요" aria-label="Permalink to &quot;메시지 흐름 (개요)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Inbound message</span></span>
<span class="line"><span>  -&gt; routing/bindings -&gt; session key</span></span>
<span class="line"><span>  -&gt; queue (if a run is active)</span></span>
<span class="line"><span>  -&gt; agent run (streaming + tools)</span></span>
<span class="line"><span>  -&gt; outbound replies (channel limits + chunking)</span></span></code></pre></div><p>주요 설정 값은 구성(configuration)에 있습니다:</p><ul><li><code>messages.*</code>: 프리픽스, 큐잉, 그룹 동작.</li><li><code>agents.defaults.*</code>: 블록 스트리밍과 청킹 기본값.</li><li>채널별 오버라이드(<code>channels.whatsapp.*</code>, <code>channels.telegram.*</code> 등): 상한과 스트리밍 토글.</li></ul><p>전체 스키마는 <a href="/openclaw-docs-ko/gateway/configuration">Configuration</a>을 참고하세요.</p><h2 id="인바운드-중복-제거-dedupe" tabindex="-1">인바운드 중복 제거 (Dedupe) <a class="header-anchor" href="#인바운드-중복-제거-dedupe" aria-label="Permalink to &quot;인바운드 중복 제거 (Dedupe)&quot;">​</a></h2><p>채널은 재연결 후 같은 메시지를 다시 전달할 수 있습니다. OpenClaw는 channel/account/peer/session/message id 기반의 단기 캐시를 유지하여 중복 전달이 또 다른 에이전트 실행을 트리거하지 않도록 합니다.</p><h2 id="인바운드-디바운싱-debouncing" tabindex="-1">인바운드 디바운싱 (Debouncing) <a class="header-anchor" href="#인바운드-디바운싱-debouncing" aria-label="Permalink to &quot;인바운드 디바운싱 (Debouncing)&quot;">​</a></h2><p><strong>동일 발신자</strong>로부터의 연속된 빠른 메시지는 <code>messages.inbound</code>를 통해 하나의 에이전트 턴으로 배치(batch)될 수 있습니다. 디바운싱은 채널 + 대화 단위로 적용되며, reply 스레딩/ID에는 가장 최근 메시지를 사용합니다.</p><p>설정(전역 기본값 + 채널별 오버라이드):</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  messages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    inbound</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      debounceMs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      byChannel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        slack</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>참고 사항:</p><ul><li>디바운싱은 <strong>텍스트 전용</strong> 메시지에만 적용됩니다. 미디어/첨부파일은 즉시 플러시됩니다.</li><li>컨트롤 명령(command)은 기본적으로 디바운싱을 우회하여 독립적으로 처리됩니다 — <strong>단</strong>, 채널이 same-sender DM coalescing에 명시적으로 옵트인한 경우(예: <a href="/openclaw-docs-ko/channels/bluebubbles#coalescing-split-send-dms-command--url-in-one-composition">BlueBubbles <code>coalesceSameSenderDms</code></a>)는 예외로, DM 명령이 디바운스 윈도우 내에서 대기하여 split-send 페이로드가 같은 에이전트 턴에 합쳐질 수 있게 됩니다.</li></ul><h2 id="세션과-디바이스" tabindex="-1">세션과 디바이스 <a class="header-anchor" href="#세션과-디바이스" aria-label="Permalink to &quot;세션과 디바이스&quot;">​</a></h2><p>세션은 클라이언트가 아닌 게이트웨이(gateway)가 소유합니다.</p><ul><li>Direct chat은 에이전트의 메인 세션 키로 통합됩니다.</li><li>그룹/채널은 각자 자신만의 세션 키를 가집니다.</li><li>세션 저장소와 transcript는 게이트웨이 호스트에 있습니다.</li></ul><p>여러 디바이스/채널이 같은 세션에 매핑될 수 있지만, 히스토리가 모든 클라이언트로 완전히 동기화되지는 않습니다. 권장: 긴 대화에서는 컨텍스트 분기를 피하기 위해 하나의 주 디바이스(primary device)를 사용하세요. Control UI와 TUI는 항상 게이트웨이 기반 세션 transcript를 표시하므로 이것이 진실의 원천(source of truth)입니다.</p><p>자세히: <a href="/openclaw-docs-ko/concepts/session">세션 관리</a>.</p><h2 id="인바운드-본문과-히스토리-컨텍스트" tabindex="-1">인바운드 본문과 히스토리 컨텍스트 <a class="header-anchor" href="#인바운드-본문과-히스토리-컨텍스트" aria-label="Permalink to &quot;인바운드 본문과 히스토리 컨텍스트&quot;">​</a></h2><p>OpenClaw는 <strong>프롬프트 본문(prompt body)</strong> 과 <strong>명령 본문(command body)</strong> 을 분리합니다:</p><ul><li><code>Body</code>: 에이전트에게 전달되는 프롬프트 텍스트. 채널 envelope와 선택적인 히스토리 래퍼를 포함할 수 있습니다.</li><li><code>CommandBody</code>: 디렉티브/명령 파싱용 원시 사용자 텍스트.</li><li><code>RawBody</code>: <code>CommandBody</code>의 레거시 별칭(호환성 유지).</li></ul><p>채널이 히스토리를 제공할 때는 공유 래퍼를 사용합니다:</p><ul><li><code>[Chat messages since your last reply - for context]</code></li><li><code>[Current message - respond to this]</code></li></ul><p><strong>non-direct chat</strong>(그룹/채널/룸)에서는 <strong>현재 메시지 본문</strong> 이 발신자 라벨로 프리픽스됩니다(히스토리 항목과 동일한 스타일). 이로써 실시간 메시지와 큐잉/히스토리 메시지가 에이전트 프롬프트에서 일관성을 유지합니다.</p><p>히스토리 버퍼는 <strong>대기 중인 것만 포함(pending-only)</strong> 합니다. 즉, 실행을 트리거하지 <em>않은</em> 그룹 메시지(예: 멘션 게이팅된 메시지)를 포함하고, 이미 세션 transcript에 있는 메시지는 <strong>제외</strong>합니다.</p><p>디렉티브 제거(directive stripping)는 히스토리를 그대로 보존하기 위해 <strong>현재 메시지</strong> 섹션에만 적용됩니다. 히스토리를 래핑하는 채널은 <code>CommandBody</code>(또는 <code>RawBody</code>)를 원본 메시지 텍스트로 설정하고 <code>Body</code>는 조합된 프롬프트로 유지해야 합니다. 히스토리 버퍼는 <code>messages.groupChat.historyLimit</code>(전역 기본값)과 <code>channels.slack.historyLimit</code> 또는 <code>channels.telegram.accounts.&lt;id&gt;.historyLimit</code> 같은 채널별 오버라이드로 설정 가능합니다(<code>0</code>이면 비활성화).</p><h2 id="큐잉과-후속-처리-queueing-and-followups" tabindex="-1">큐잉과 후속 처리 (Queueing and followups) <a class="header-anchor" href="#큐잉과-후속-처리-queueing-and-followups" aria-label="Permalink to &quot;큐잉과 후속 처리 (Queueing and followups)&quot;">​</a></h2><p>이미 실행이 활성화된 경우, 인바운드 메시지는 큐에 쌓이거나, 현재 실행으로 유도(steer)되거나, 다음 후속 턴을 위해 수집(collect)될 수 있습니다.</p><ul><li><code>messages.queue</code>(및 <code>messages.queue.byChannel</code>)로 설정합니다.</li><li>모드: <code>interrupt</code>, <code>steer</code>, <code>followup</code>, <code>collect</code>, 그리고 backlog 변형.</li></ul><p>자세히: <a href="/openclaw-docs-ko/concepts/queue">큐잉</a>.</p><h2 id="스트리밍-청킹-배칭" tabindex="-1">스트리밍, 청킹, 배칭 <a class="header-anchor" href="#스트리밍-청킹-배칭" aria-label="Permalink to &quot;스트리밍, 청킹, 배칭&quot;">​</a></h2><p>블록 스트리밍(block streaming)은 모델이 텍스트 블록을 생성하는 대로 부분 응답을 전송합니다. 청킹(chunking)은 채널 텍스트 제한을 존중하며 fenced code를 쪼개지 않도록 합니다.</p><p>주요 설정:</p><ul><li><code>agents.defaults.blockStreamingDefault</code> (<code>on|off</code>, 기본값 off)</li><li><code>agents.defaults.blockStreamingBreak</code> (<code>text_end|message_end</code>)</li><li><code>agents.defaults.blockStreamingChunk</code> (<code>minChars|maxChars|breakPreference</code>)</li><li><code>agents.defaults.blockStreamingCoalesce</code> (idle 기반 배칭)</li><li><code>agents.defaults.humanDelay</code> (블록 응답 사이의 사람처럼 느껴지는 지연)</li><li>채널 오버라이드: <code>*.blockStreaming</code> 및 <code>*.blockStreamingCoalesce</code> (Telegram이 아닌 채널은 <code>*.blockStreaming: true</code>를 명시적으로 설정해야 함)</li></ul><p>자세히: <a href="/openclaw-docs-ko/concepts/streaming">스트리밍 + 청킹</a>.</p><h2 id="reasoning-가시성과-토큰" tabindex="-1">Reasoning 가시성과 토큰 <a class="header-anchor" href="#reasoning-가시성과-토큰" aria-label="Permalink to &quot;Reasoning 가시성과 토큰&quot;">​</a></h2><p>OpenClaw는 모델의 reasoning을 노출하거나 숨길 수 있습니다:</p><ul><li><code>/reasoning on|off|stream</code>으로 가시성을 제어합니다.</li><li>모델이 reasoning 콘텐츠를 생성하면, 그 내용은 여전히 토큰 사용량에 포함됩니다.</li><li>Telegram은 reasoning 스트리밍을 draft bubble로 지원합니다.</li></ul><p>자세히: <a href="/openclaw-docs-ko/tools/thinking">Thinking + reasoning 디렉티브</a> 및 <a href="/openclaw-docs-ko/reference/token-use">토큰 사용량</a>.</p><h2 id="프리픽스-스레딩-응답" tabindex="-1">프리픽스, 스레딩, 응답 <a class="header-anchor" href="#프리픽스-스레딩-응답" aria-label="Permalink to &quot;프리픽스, 스레딩, 응답&quot;">​</a></h2><p>아웃바운드 메시지 포맷은 <code>messages</code>에 중앙화되어 있습니다:</p><ul><li><code>messages.responsePrefix</code>, <code>channels.&lt;channel&gt;.responsePrefix</code>, <code>channels.&lt;channel&gt;.accounts.&lt;id&gt;.responsePrefix</code> (아웃바운드 프리픽스 캐스케이드), 그리고 <code>channels.whatsapp.messagePrefix</code>(WhatsApp 인바운드 프리픽스)</li><li><code>replyToMode</code> 및 채널별 기본값을 통한 reply 스레딩</li></ul><p>자세히: <a href="/openclaw-docs-ko/gateway/config-agents#messages">Configuration</a> 및 채널 문서.</p><h2 id="조용한-응답-silent-replies" tabindex="-1">조용한 응답 (Silent replies) <a class="header-anchor" href="#조용한-응답-silent-replies" aria-label="Permalink to &quot;조용한 응답 (Silent replies)&quot;">​</a></h2><p>정확한 silent 토큰인 <code>NO_REPLY</code> / <code>no_reply</code>는 &quot;사용자에게 보이는 응답을 전달하지 말 것&quot;을 의미합니다. OpenClaw는 대화 유형에 따라 이 동작을 결정합니다:</p><ul><li>Direct 대화에서는 기본적으로 silence를 허용하지 않으며, 단순한 silent 응답은 짧은 visible fallback으로 재작성됩니다.</li><li>그룹/채널은 기본적으로 silence를 허용합니다.</li><li>내부 오케스트레이션(internal orchestration)은 기본적으로 silence를 허용합니다.</li></ul><p>기본값은 <code>agents.defaults.silentReply</code>와 <code>agents.defaults.silentReplyRewrite</code>에 있으며, <code>surfaces.&lt;id&gt;.silentReply</code>와 <code>surfaces.&lt;id&gt;.silentReplyRewrite</code>로 surface별 오버라이드가 가능합니다.</p><p>부모 세션이 하나 이상의 대기 중(pending) 스폰된 서브에이전트(subagent) 실행을 가지고 있을 때는, bare silent 응답이 모든 surface에서 재작성 대신 드롭됩니다. 이렇게 하면 자식(child) 완료 이벤트가 실제 응답을 전달할 때까지 부모가 조용히 대기합니다.</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/streaming">스트리밍</a> — 실시간 메시지 전달</li><li><a href="/openclaw-docs-ko/concepts/retry">재시도</a> — 메시지 전달 재시도 동작</li><li><a href="/openclaw-docs-ko/concepts/queue">큐</a> — 메시지 처리 큐</li><li><a href="/openclaw-docs-ko/channels/">채널</a> — 메시징 플랫폼 통합</li></ul>`,51)])])}const u=s(l,[["render",o]]);export{g as __pageData,u as default};
